INSERT INTO `thong_bao` VALUES (1,_binary '\0','ALL',_binary '','2026-01-20 08:00:00.000000','Phòng Đào tạo','Sinh viên đăng ký học phần từ ngày 26/01/2026 đến 25/02/2026. Vui lòng đăng ký đúng hạn.','Lịch đăng ký học phần kỳ 2 năm 2025-2026'),(2,_binary '\0','ALL',_binary '\0','2026-04-10 09:00:00.000000','Ban Giám hiệu','Trường thông báo lịch nghỉ lễ 30/4 và 1/5. SV nghỉ học từ 30/04 đến 01/05/2026.','Thông báo nghỉ lễ 30/4 - 1/5'),(3,_binary '\0','ALL',_binary '','2026-02-15 10:00:00.000000','Phòng Tài chính','SV chưa hoàn thành học phí kỳ 2 vui lòng nộp trước 28/02/2026. Sau thời hạn sẽ bị khoá đăng ký.','Nhắc nhở nộp học phí kỳ 2'),(4,_binary '\0','ALL',_binary '\0','2026-04-05 14:00:00.000000','Khoa CNTT','FPT Software tuyển thực tập sinh kỳ hè 2026. Ưu tiên SV năm 3-4 ngành CNTT. Nộp CV trước 15/05/2026.','Tuyển dụng thực tập sinh CNTT tại FPT Software'),(5,_binary '\0','ALL',_binary '\0','2026-04-14 15:38:15.967692','','tt','ttt');
